const express = require('express');
const axios = require('axios');
const crypto = require('crypto');

const app = express();
const port = 3000;
const apiKeySecret = 'your_api_key_secret';

app.use(express.json());

app.all('*', async (req, res) => {
    const apiKey = req.query.api_key;

    if (!apiKey) {
        return res.status(401).send('API key is required');
    }

    try {
        // Validate API key
        const isValidApiKey = await validateApiKey(apiKey);
        if (!isValidApiKey) {
            return res.status(403).send('Invalid API key');
        }

        // Forward request to backend service
        const backendUrl = 'http://backend-service.com' + req.originalUrl;
        const headers = { ...req.headers, 'X-API-Key': apiKey };

        try {
            const response = await axios({
                method: req.method,
                url: backendUrl,
                headers,
                data: req.body
            });

            res.status(response.status).send(response.data);
        } catch (error) {
            console.error('Backend service error:', error.response ? error.response.data : error.message);
            res.status(error.response ? error.response.status : 500).send('Internal Server Error');
        }
    } catch (error) {
        console.error('API key validation error:', error);
        res.status(500).send('Internal Server Error');
    }
});

async function validateApiKey(apiKey) {
    // Implement your API key validation logic here
    // For example, check if the apiKey is in a whitelist or matches a hash of a secret
    const expectedHash = crypto.createHmac('sha256', apiKeySecret).digest('hex');
    return apiKey === expectedHash;
}

app.listen(port, () => {
    console.log(`API gateway listening at http://localhost:${port}`);
});